export const collectingFaqItems = [
  // Vinyl Records
  { hobbyId: "vinyl-records", question: "What turntable should I start with?", answer: "Audio-Technica AT-LP60X (CHF 120) is the go-to entry model. Avoid suitcase turntables — they damage records and sound terrible.", upvotes: 54 },
  { hobbyId: "vinyl-records", question: "Are vinyl records actually better than digital?", answer: "Not objectively — but the ritual, artwork, and intentional listening make the experience different and special. It's about the ritual, not the frequency response.", upvotes: 42 },
  { hobbyId: "vinyl-records", question: "Where should I buy records?", answer: "Local record shops and flea markets for crate digging. Discogs.com for specific titles. New releases from your favorite artists' websites.", upvotes: 38 },

  // Vintage Cameras
  { hobbyId: "vintage-cameras", question: "Which film camera is best for beginners?", answer: "Canon AE-1, Pentax K1000, or Olympus OM-1. All are reliable, well-documented, and have cheap lenses available.", upvotes: 51 },
  { hobbyId: "vintage-cameras", question: "How much does film photography cost per shot?", answer: "About CHF 0.50-0.80 per shot including development. A 36-exposure roll costs ~CHF 8-12, development ~CHF 10-15.", upvotes: 45 },
  { hobbyId: "vintage-cameras", question: "Is film photography worth it in 2025?", answer: "If you value the learning process, intentional shooting, and the unique look of film — absolutely. It teaches you more about photography than digital ever will.", upvotes: 39 },

  // Plants
  { hobbyId: "plants", question: "What's the hardest plant to kill?", answer: "Pothos, snake plant, and ZZ plant are nearly indestructible. They tolerate low light and irregular watering. Perfect for beginners.", upvotes: 62 },
  { hobbyId: "plants", question: "How often should I water my plants?", answer: "It depends on the species, but a good rule: stick your finger 2cm into the soil. If it's dry, water. If moist, wait. Overwatering kills more plants than anything.", upvotes: 55 },

  // Coins
  { hobbyId: "coins", question: "Are old coins I find in change worth anything?", answer: "Sometimes! Pre-1960s Swiss coins contain silver. Any coin in unusually good condition or with a minting error could have collector value. Start checking your change.", upvotes: 47 },
  { hobbyId: "coins", question: "Why should I never clean coins?", answer: "Cleaning removes the natural patina (toning) that collectors prize. A cleaned coin can lose 50-90% of its collector value. Even gentle cleaning is obvious to experts.", upvotes: 41 },

  // Stamps
  { hobbyId: "stamps", question: "Is stamp collecting dead?", answer: "Not at all — it's evolved. Fewer young collectors means less competition and lower prices for great stamps. Online communities are thriving on Reddit and specialized forums.", upvotes: 38 },
  { hobbyId: "stamps", question: "How do I tell if a stamp is valuable?", answer: "Rarity, condition, and demand. Use a catalog (Michel for Europe, Scott for USA) to identify. Most stamps are common, but errors, early issues, and high-denomination stamps can be valuable.", upvotes: 34 },
];

